commands_run.command:
node - <<'NODE'
import { mkdtempSync, mkdirSync, writeFileSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { resolve } from 'node:path';
import { diffAdversarialDevWorkerTreatmentVsSmoke } from './scripts/effectiveness/diff-adversarial-dev-worker-treatment-vs-smoke.ts';
import { ADVERSARIAL_TREATMENT_DEV_WORKER_PHASE, adversarialDevWorkerPromptHash, buildAdversarialDevWorkerPrompt } from './src/effectiveness/adversarial-dev-worker-stage.ts';
const repoRoot=mkdtempSync(resolve(tmpdir(),'diff-debug-'));
const reportDir=resolve(repoRoot,'evals/effectiveness/reports/adversarial-prompt-injection-001');
mkdirSync(resolve(reportDir,'sdk-stage-logs'),{recursive:true});
writeFileSync(resolve(reportDir,'adversarial-dev-worker-smoke-exact-result.json'), JSON.stringify({status:'PASS',mode:'exact',target_repo_is_git:true,prompt_length:buildAdversarialDevWorkerPrompt().length,prompt_hash:adversarialDevWorkerPromptHash()},null,2));
writeFileSync(resolve(reportDir,'treatment-result.json'), JSON.stringify({case_id:'adversarial-prompt-injection-001',variant:'treatment',mode:'treatment',status:'PASS',dev_worker_prompt_length:buildAdversarialDevWorkerPrompt().length,dev_worker_prompt_hash:adversarialDevWorkerPromptHash(),validation_commands:['npm test','npm run security:contract'],dev_worker_phase:ADVERSARIAL_TREATMENT_DEV_WORKER_PHASE,finalizer_read_only:true},null,2));
writeFileSync(resolve(reportDir,'sdk-stage-logs/adversarial-dev-worker-invocation-trace-redacted.json'), JSON.stringify({target_repo_is_git:true,start_thread_options:{workingDirectory:resolve(repoRoot,'evals/effectiveness/runs/adversarial-prompt-injection-001/treatment/target-repo'),sandboxMode:'workspace-write',model:'gpt-test'},run_options:{outputSchemaWasPassedToSdk:true},prompt:{length:buildAdversarialDevWorkerPrompt().length,hash:adversarialDevWorkerPromptHash()},sdk_api_method:'run'},null,2));
const diff=diffAdversarialDevWorkerTreatmentVsSmoke(repoRoot);
console.log(JSON.stringify({status:diff.status,cats:diff.mismatch_categories,fields:Object.fromEntries(Object.entries(diff.fields).filter(([k,v])=>!v.same&&v.critical))},null,2));
rmSync(repoRoot,{recursive:true,force:true});
NODE
